// Normalize payload and classify tier exactly matching config.py TIERS
const body = $input.first().json.body || $input.first().json;
const now  = new Date().toISOString();
const score = body.risk_score || 0;

// Exact match of config.py TIERS:
// (70, CRITICAL, QUARANTINE)
// (61, HIGH,     JUNK)
// (31, MEDIUM,   FLAG)
// (0,  LOW,      ALLOW)
let tier, outlook_action;
if      (score >= 70) { tier = 'CRITICAL'; outlook_action = 'QUARANTINE'; }
else if (score >= 61) { tier = 'HIGH';     outlook_action = 'JUNK'; }
else if (score >= 31) { tier = 'MEDIUM';   outlook_action = 'FLAG'; }
else                  { tier = 'LOW';      outlook_action = 'ALLOW'; }

const tierColors = {
  CRITICAL: '#dc3545',
  HIGH:     '#fd7e14',
  MEDIUM:   '#ffc107',
  LOW:      '#28a745'
};

return [{
  json: {
    incident_id:       `FS-${Date.now()}`,
    logged_at:         now,
    risk_score:        score,
    tier:              tier,
    outlook_action:    outlook_action,
    verdict:           body.verdict                  || 'UNKNOWN',
    prediction_id:     body.prediction_id            || null,
    ai_generated_prob: body.ai_generated_probability || 0,
    roberta_prob:      body.roberta_phishing_prob     || 0,
    top_indicators:    body.top_indicators            || [],
    header_flags:      body.header_flags              || [],
    injection_score:   body.injection_score           || 0,
    email_preview:     body.email_preview             || '',
    source:            body.source                   || 'outlook_plugin',
    tier_color:        tierColors[tier],
    requires_approval: tier === 'CRITICAL',
    raw:               body
  }
}];

const d = $input.first().json;
const now = new Date().toISOString();
console.log(`[LOW] Incident ${d.incident_id} score ${d.risk_score} — logged quietly`);
return [{ json: { ...d, action_taken: 'LOGGED_QUIETLY', logged_at: now, workflow_complete: true } }];

const d = $input.first().json;
const now = new Date().toISOString();
console.log(`[MEDIUM] Incident ${d.incident_id} score ${d.risk_score} — flagged for review`);
return [{ json: { ...d, action_taken: 'FLAGGED', logged_at: now, workflow_complete: true } }];

values.content:
=Generate a security incident summary for the following fraud detection result:

Risk Score: {{ $json.risk_score }}/100
Tier: {{ $json.tier }}
Verdict: {{ $json.verdict }}
Outlook Action: {{ $json.outlook_action }}
Top Indicators: {{ $json.top_indicators.slice(0,5).join(', ') }}
Header Flags: {{ $json.header_flags.slice(0,3).join(', ') }}
AI Generated Probability: {{ Math.round($json.ai_generated_prob * 100) }}%
RoBERTa Phishing Confidence: {{ Math.round($json.roberta_prob * 100) }}%
Prompt Injection Score: {{ $json.injection_score }}/100

Write exactly 2-3 sentences for a security analyst. Mention risk score, tier, and recommended action explicitly.

=Brief summary for HIGH risk email:
Risk Score: {{ $json.risk_score }}/100, Tier: {{ $json.tier }}
Top Indicators: {{ $json.top_indicators.slice(0,3).join(', ') }}
Verdict: {{ $json.verdict }}
Write 2 sentences for analyst review.

