// Merge CRITICAL LLM summary with incident
const incident  = $('Enrich + Classify Tier').first().json;
const llmOutput = $input.first().json;
const summary   = llmOutput.content || llmOutput.text || llmOutput.message?.content || 'LLM unavailable — CRITICAL risk, review immediately.';
const now       = new Date().toISOString();

return [{
  json: {
    ...incident,
    llm_summary:  summary,
    audit_trail:  `[${now}] FraudShield CRITICAL alert. Score: ${incident.risk_score}/100. Action: ${incident.outlook_action}. LLM: ${summary}`
  }
}];

// Merge HIGH LLM summary with incident
const incident  = $('Enrich + Classify Tier').first().json;
const llmOutput = $input.first().json;
const summary   = llmOutput.content || llmOutput.text || llmOutput.message?.content || 'HIGH risk email — review and consider moving to junk.';
const now       = new Date().toISOString();

return [{
  json: {
    ...incident,
    llm_summary:  summary,
    audit_trail:  `[${now}] FraudShield HIGH alert. Score: ${incident.risk_score}/100. Action: ${incident.outlook_action}. LLM: ${summary}`
  }
}];

// Build HIGH notification — no approval needed, just alert
const d = $input.first().json;
const indicators = (d.top_indicators || []).slice(0, 3).join(' | ');
return [{
  json: {
    ...d,
    slack_text: `*[HIGH] FraudShield Alert*\nScore: *${d.risk_score}/100* | Action: *${d.outlook_action}*\nVerdict: ${d.verdict} | AI: ${Math.round(d.ai_generated_prob*100)}%\nSummary: ${d.llm_summary}\nIndicators: ${indicators}\nIncident: ${d.incident_id}`,
    notification_sent: true
  }
}];

// HIGH path complete — log and done
const d = $input.first().json;
const now = new Date().toISOString();
console.log(`[HIGH] Incident ${d.incident_id} score ${d.risk_score} — Slack notified, no approval needed`);
return [{ json: { ...d, action_taken: 'HIGH_NOTIFIED', completed_at: now, workflow_complete: true } }];

const incident = $('Merge CRITICAL + LLM').first().json;
const now = new Date().toISOString();
return [{
  json: {
    ...incident,
    action_taken:        'QUARANTINE_CONFIRMED',
    analyst_decision:    'QUARANTINE',
    analyst_decision_at: now,
    audit_trail:         incident.audit_trail + ` [${now}] Human analyst APPROVED quarantine.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'PHISHING',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes: `n8n CRITICAL workflow: analyst approved quarantine for ${incident.incident_id}`
    }
  }
}];

const incident = $('Merge CRITICAL + LLM').first().json;
const now = new Date().toISOString();
return [{
  json: {
    ...incident,
    action_taken:        'FALSE_POSITIVE',
    analyst_decision:    'SAFE',
    analyst_decision_at: now,
    audit_trail:         incident.audit_trail + ` [${now}] Human analyst marked FALSE POSITIVE — queued for retraining.`,
    feedback_payload: {
      prediction_id: incident.prediction_id,
      user_verdict:  'LEGITIMATE',
      model_verdict: incident.verdict,
      model_score:   incident.risk_score,
      notes: `n8n CRITICAL workflow: analyst marked false positive for ${incident.incident_id}`
    }
  }
}];

const d = $input.first().json;
const now = new Date().toISOString();
console.log('=== QUARANTINE CONFIRMED ===');
console.log(JSON.stringify({ incident_id: d.incident_id, score: d.risk_score, action: d.action_taken, at: now, audit: d.audit_trail }, null, 2));
return [{ json: { ...d, final_audit_at: now, workflow_complete: true } }];

const d = $input.first().json;
const now = new Date().toISOString();
console.log('=== FALSE POSITIVE — RETRAINING QUEUED ===');
console.log(JSON.stringify({ incident_id: d.incident_id, score: d.risk_score, action: d.action_taken, retraining: true, at: now, audit: d.audit_trail }, null, 2));
